com.mirth.connect.plugins.javascriptrule.script:
if (   msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A01"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A04"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A05"
    //|| msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A08"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A11"// && msg['PV1']['PV1.2']['PV1.2.1'].toString() == 'O')  // Cancel attendance for outpatients, i.e. reset status to scheduled
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A03"  // Inpatient discharge
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A13"  // Inpatient cancel discharge
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A02"  // Inpatient transfer
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A12"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "S12"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "S13"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "S14"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "S26"
   )
