com.mirth.connect.plugins.javascriptstep.script:
var obxs = msg["OBX"];

for each(var obx in msg.OBX) {
	var filename = obx["OBX.3"]["OBX.3.3"];
	var extension = filename.substr(filename.length - 4);
	var contentType = "application/blob";

	if(extension == ".png" || extension == ".PNG") {
		contentType = "image/png";
	}
	if(extension == ".jpg" || extension == ".JPG") {
		contentType = "image/jpeg";
	}
	if(extension == ".pdf" || extension == ".PDF") {
		contentType = "application/pdf";
	}

	var mapping = {
		"filename": filename,
		"patientId": channelMap.get("PatientId"),
		"contentType": contentType,
		"patientIdentifier": channelMap.get("PatientIdentifier"),
		"hospitalNumber": channelMap.get("HospitalNumber"),
		"bookingType" : channelMap.get("BookingType"),
		};

	var attachement = FileUtil.decode(obx["OBX.5"]["OBX.5.5"]);
	//.replace("\n", "");

	router.routeMessage("Generic Document processor",new RawMessage(attachement, null, new java.util.HashMap(mapping)));
};

